package be.schaubroeck.lpb.rkm.rekenmotor.check;

import be.schaubroeck.lpb.rkm.rekenmotor.RekenContext;
import be.schaubroeck.lpb.rkm.rekenmotor.RekenTijd;
import be.schaubroeck.lpb.rkm.rekenmotor.results.RekenResultatenBeheer;
import be.schaubroeck.lpb.rkm.rekenmotor.util.HashMoneyMap;
import be.schaubroeck.lpb.rkm.rekenmotor.util.MoneyMap;
import be.schaubroeck.lpb.rkm.rekenmotor.util.PersoonsDataManager;
import be.schaubroeck.lpb.tools.Money;
import be.schaubroeck.lpb.tools.RekenBedrag;
import be.schaubroeck.lpb.tools.RekenHoofd;
import be.schaubroeck.lpb.tools.RekenLijn;
import be.schaubroeck.lpb.tools.enumtypes.OpslaanNulResultaten;
import be.schaubroeck.lpb.tools.enumtypes.RekenBedragType;
import com.google.common.collect.ImmutableSet;
import lombok.Setter;

import java.util.ArrayList;
import java.util.Collection;
import java.util.List;
import java.util.Optional;
import java.util.Set;
import java.util.stream.Collectors;

import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenChainKey.PERSOONSDATA_MANAGER_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenChainKey.SLEUTEL_TUSSENKOMSTEN;

public class NieuweResultatenMetBvRelatedBedragen {

    private static final Set<RekenBedragType> BV_RELATED_BEDRAGTYPES = ImmutableSet.of(
            RekenBedragType.BEDRIJFSVOORHEFFING,
            RekenBedragType.BEDRIJFSVOORHEFFING_ACHTERSTAL,
            RekenBedragType.VERMINDERING_BEDRIJFSVOORHEFFING_WERKBONUS_LUIK_A,
            RekenBedragType.VERMINDERING_BEDRIJFSVOORHEFFING_WERKBONUS_LUIK_B,
            RekenBedragType.VERMINDERING_BEDRIJFSVOORHEFFING_INHOUDINGEN,
            RekenBedragType.VLAAMSE_VERMINDERING_BEDRIJFSVOORHEFFING);

    private List<RekenHoofd> bestaanden;
    private List<RekenHoofd> sleutelTussenkomsten;
    private RekenContext context;

    @Setter
    private RekenResultatenBeheer rekenResultatenBeheer = new RekenResultatenBeheer();

    public void fillParams(RekenContext context) {
        this.context = context;
        PersoonsDataManager persoonsDataManager = context.getUnchecked(PERSOONSDATA_MANAGER_KEY);
        RekenTijd rekenTijd = context.getRekenTijd();
        this.bestaanden = persoonsDataManager.getBestaandeRekenResultaten(rekenTijd.beginDatum);
        this.sleutelTussenkomsten = Optional.ofNullable((List<RekenHoofd>) context.getUnchecked(SLEUTEL_TUSSENKOMSTEN)).orElse(new ArrayList<>());
    }

    public boolean check(RekenContext context) {
        fillParams(context);
        List<RekenHoofd> outputs = vormNieuweRekenHoofden();
        MoneyMap<RegimeBedragTypeKey> bvBedragenMap = new HashMoneyMap<>();
        outputs.stream()
                .map(RekenHoofd::getRekenLijnen).flatMap(Collection::stream)
                .map(RekenLijn::getRekenBedragen).flatMap(Collection::stream)
                .filter(this::isBvRelatedBedragType)
                .forEach(x -> bvBedragenMap.addToMoney(new RegimeBedragTypeKey(x), x.getBedrag()));
        return bvBedragenMap.values().stream().anyMatch(this::isBedragVerschillendVanNul);
    }

    private List<RekenHoofd> vormNieuweRekenHoofden() {
        List<RekenHoofd> gelockten = bestaanden.stream().filter(t -> t.getRnummer() != null).collect(Collectors.toList());
        gelockten.addAll(sleutelTussenkomsten);
        List<RekenHoofd> outputs = rekenResultatenBeheer.maakRekenResultaten(context, gelockten, OpslaanNulResultaten.NIET_OPSLAAN);
        outputs.forEach(this::setParents);
        return outputs;
    }

    private void setParents(RekenHoofd hoofd) {
        for (RekenLijn rekenLijn : hoofd.getRekenLijnen()) {
            rekenLijn.setRekenHoofd(hoofd);
            setParents(rekenLijn);
        }
    }

    private void setParents(RekenLijn lijn) {
        for (RekenBedrag rekenBedrag : lijn.getRekenBedragen()) {
            rekenBedrag.setRekenLijn(lijn);
        }
    }

    private boolean isBedragVerschillendVanNul(Money bedrag) {
        return bedrag.signum() != 0;
    }

    private boolean isBvRelatedBedragType(RekenBedrag rekenBedrag) {
        return BV_RELATED_BEDRAGTYPES.contains(rekenBedrag.getBedragType());
    }


}
